async function () {
  const url = 'http://192.168.1.101:30109/webhook/timers';
  try {
    const res = await fetch(url, {
      method: 'GET'
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const json = await res.json();
    const rows = TimerController._normalize(json);
    await storeValue('timersRaw', rows, false);
    await storeValue('lastRefreshMs', Date.now(), false);
    await storeValue('lastError', '', false);
    return rows;
  } catch (e) {
    await storeValue('lastError', String(e?.message || e), false);
    return appsmith.store.timersRaw || [];
  }
}

