function () {
  const now = appsmith.store.uiNowMs || Date.now();
  const rows = appsmith.store.timersRaw || [];
  return rows.map((r, idx) => {
    const id = r.id ?? r.timerId ?? `row-${idx + 1}`;
    const ts = Number(r.timestamp ?? r.ts ?? r.lastPress ?? 0);
    const validTs = Number.isFinite(ts) ? ts : 0;
    const ageSec = validTs > 0 ? Math.max(0, Math.floor((now - validTs) / 1000)) : null;
    const howLongAgo = TimerController._humanAge(ageSec);
    return {
      id,
      timestamp_ms: validTs || null,
      updated_at_local: validTs > 0 ? new Date(validTs).toLocaleString() : '',
      age_seconds: ageSec,
      how_long_ago: howLongAgo,
      source: JSON.stringify(r)
    };
  });
}

